        # 构建入度表和邻接表
        in_degrees = [0 for _ in range(numCourses)]
        adj = [set() for _ in range(numCourses)]
        for course, pre in prerequisites:
            in_degrees[course] += 1
            adj[pre].add(course)
        # 使用队列
        res = []
        q = []
        for i in range(numCourses):
            if in_degrees[i] == 0:
                q.append(i)

